sp_page.css:
.rich-carousel-widget .panel {
    background: $panel-bg; // #FFFFFF
    padding: 10px;
    margin: $sp-space--xl $sp-space--lg;
    border-radius: $border-radius-large;
    -webkit-box-shadow: $sp-panel-box-shadow;
    box-shadow: $sp-panel-box-shadow;
    border: 1px solid darken($body-bg, 5%);
}

.topic-breadcrumbs-container .breadcrumbs {
    padding-top: 1.375rem;
    margin-left: 0.9375rem;
    
    .nav {
        .fa {
            color: $text-muted; // #6C757D
        }
        
        a {
            color: $link-color; // #0076D6
            
            &:hover {
                color: $brand-primary; // #D72828
            }
        }
    }
}

[accessibility] [tabindex]:focus,
[accessibility] .btn.btn-default:focus {
    box-shadow: 0rem 0rem 0rem 0.15rem $brand-primary; // #D72828
}
